 83          free(fb_storage);
 84          hal_display_deinitialize();
 85          return EXIT_FAILURE;
 86      }
 87
 88      if (!gfx_fill(&framebuffer, COLOR_BLACK) || !gfx_flush(&framebuffer)) {
 89          fprintf(stderr, "Error: initial framebuffer clear/flush failed\n");
 90          gfx_framebuffer_unbind(&framebuffer);
 91          free(fb_storage);
 92          hal_display_deinitialize();
 93          return EXIT_FAILURE;
 94      }
 95
 96      static const struct {
 97          uint16_t    color;
 98          const char *name;
 99      } colors[] = {
100          { COLOR_RED,     "Red"     },
101          { COLOR_GREEN,   "Green"   },
102          { COLOR_BLUE,    "Blue"    },
103          { COLOR_WHITE,   "White"   },
104          { COLOR_BLACK,   "Black"   },
105          { COLOR_YELLOW,  "Yellow"  },
106          { COLOR_CYAN,    "Cyan"    },
107          { COLOR_MAGENTA, "Magenta" }
108      };
109
110      int color_count = (int)(sizeof(colors) / sizeof(colors[0]));
111
112      uint16_t path_left = PATH_MARGIN;
113      uint16_t path_top = PATH_MARGIN;
114      uint16_t path_right = DISPLAY_WIDTH - PATH_MARGIN - DIRTY_BOX_SIZE;
115      uint16_t path_bottom = DISPLAY_HEIGHT - PATH_MARGIN - DIRTY_BOX_SIZE;
116
117      if (path_right <= path_left || path_bottom <= path_top) {
118          fprintf(stderr, "Error: dirty region path does not fit display\n");
119          gfx_framebuffer_unbind(&framebuffer);
120          free(fb_storage);
121          hal_display_deinitialize();
122          return EXIT_FAILURE;
123      }
124
125      uint16_t box_x = path_left;
126      uint16_t box_y = path_top;
127      int color_index = 0;
128      move_direction_t direction = MOVE_RIGHT;
129
130      while (1) {
131          uint16_t box_x2 = box_x + DIRTY_BOX_SIZE - 1U;
132          uint16_t box_y2 = box_y + DIRTY_BOX_SIZE - 1U;
133
134          if (!gfx_draw_filled_rectangle(&framebuffer, box_x, box_y, box_x2, box_y2, colors[color_index].color)) {
135              fprintf(stderr, "Error: framebuffer draw failed while drawing %s\n", colors[color_index].name);
136              gfx_framebuffer_unbind(&framebuffer);
137              free(fb_storage);
138              hal_display_deinitialize();
139              return EXIT_FAILURE;
140          }
141
142          if (!gfx_flush_dirty(&framebuffer)) {
143              fprintf(stderr, "Error: dirty flush failed while drawing %s\n", colors[color_index].name);
144              gfx_framebuffer_unbind(&framebuffer);
145              free(fb_storage);
146              hal_display_deinitialize();
147              return EXIT_FAILURE;
148          }
149
150          color_index = (color_index + 1) % color_count;
151
152          switch (direction) {
153          case MOVE_RIGHT:
154              if (box_x < path_right) {
155                  box_x++;
156              } else {
157                  direction = MOVE_DOWN;
158                  box_y++;
159              }
160              break;
161          case MOVE_DOWN:
162              if (box_y < path_bottom) {
163                  box_y++;
164              } else {
165                  direction = MOVE_LEFT;
166                  box_x--;
167              }
168              break;
169          case MOVE_LEFT:
170              if (box_x > path_left) {
171                  box_x--;
172              } else {
173                  direction = MOVE_UP;
174                  box_y--;
175              }
176              break;
177          case MOVE_UP:
178          default:
179              if (box_y > path_top) {
180                  box_y--;
181              } else {
182                  direction = MOVE_RIGHT;
183                  box_x++;
184              }
185              break;
186          }
187
188          usleep(FRAME_DELAY_MS * 1000U);
189      }
190
191      /* Unreachable in this demo */
192      gfx_framebuffer_unbind(&framebuffer);
193      free(fb_storage);
194      hal_display_deinitialize();
195
196      return EXIT_SUCCESS;
197  }
